import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { fetchWaitlist, leaveWaitlist } from '../features/waitlist/waitlistSlice';

export default function WaitlistPage() {
  const dispatch = useDispatch();
  const { entries } = useSelector(s => s.waitlist);
  const [date, setDate] = useState('');

  useEffect(() => { dispatch(fetchWaitlist(date ? { date } : {})); }, [date]);

  return (
    <div style={styles.wrap}>
      <h2>My Waitlist</h2>
      <input style={styles.input} type="date" value={date} onChange={e => setDate(e.target.value)} />
      {entries.length === 0 ? <p>No waitlist entries.</p> : entries.map(e => (
        <div key={e.id} style={styles.card}>
          <div style={styles.row}>
            <span>{e.date} — {e.guests} guests</span>
            <span style={{ color: e.notified ? 'green' : '#aaa' }}>{e.notified ? '✓ Notified' : 'Waiting'}</span>
          </div>
          <button style={styles.btn} onClick={() => dispatch(leaveWaitlist(e.id))}>Leave</button>
        </div>
      ))}
    </div>
  );
}

const styles = {
  wrap:  { maxWidth: 700, margin: '32px auto', padding: '0 16px' },
  input: { padding: '8px', border: '1px solid #ddd', borderRadius: 4, marginBottom: 20 },
  card:  { background: '#fff', padding: 16, borderRadius: 8, marginBottom: 12, boxShadow: '0 1px 6px rgba(0,0,0,0.08)' },
  row:   { display: 'flex', justifyContent: 'space-between', marginBottom: 8 },
  btn:   { padding: '6px 14px', background: '#e74c3c', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' },
};
